SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `username` varchar(100) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `role` enum('ADMIN','REPARTIDOR') NOT NULL DEFAULT 'REPARTIDOR',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `streets`;
CREATE TABLE `streets` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=412 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `demarcations`;
CREATE TABLE `demarcations` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `street_id` int(11) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_user_street` (`user_id`,`street_id`),
  KEY `street_id` (`street_id`),
  CONSTRAINT `demarcations_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `demarcations_ibfk_2` FOREIGN KEY (`street_id`) REFERENCES `streets` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=412 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_notificacion` varchar(10) NOT NULL,
  `recipient_name` varchar(255) NOT NULL,
  `full_address` varchar(255) NOT NULL,
  `street_id` int(11) DEFAULT NULL,
  `assigned_user_id` int(11) DEFAULT NULL,
  `status` enum('PENDIENTE','1ER_INTENTO','ENTREGADA','DEVUELTA','FALLIDA') DEFAULT 'PENDIENTE',
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `company` varchar(50) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `street_id` (`street_id`),
  KEY `assigned_user_id` (`assigned_user_id`),
  CONSTRAINT `notifications_ibfk_1` FOREIGN KEY (`street_id`) REFERENCES `streets` (`id`) ON DELETE SET NULL,
  CONSTRAINT `notifications_ibfk_2` FOREIGN KEY (`assigned_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1008 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `delivery_attempts`;
CREATE TABLE `delivery_attempts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `notification_id` int(11) NOT NULL,
  `attempt_number` int(11) NOT NULL CHECK (`attempt_number` in (1,2)),
  `timestamp` datetime NOT NULL DEFAULT current_timestamp(),
  `status_result` enum('ENTREGADA','AUSENTE','REHUSADO','DESCONOCIDO') NOT NULL,
  `receiver_name` varchar(255) DEFAULT NULL,
  `receiver_dni` varchar(20) DEFAULT NULL,
  `signature_base64` longtext DEFAULT NULL,
  `delivered_by` int(11) NOT NULL,
  `notes` text DEFAULT NULL,
  `company` varchar(50) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unq_notification_attempt` (`notification_id`,`attempt_number`),
  KEY `delivered_by` (`delivered_by`),
  CONSTRAINT `delivery_attempts_ibfk_1` FOREIGN KEY (`notification_id`) REFERENCES `notifications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `delivery_attempts_ibfk_2` FOREIGN KEY (`delivered_by`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

SET FOREIGN_KEY_CHECKS = 1;
